    businessOrder := []string{"electronics", "grocery", "pharmacy", "restaurant"}

    // Filter valid coupons based on the conditions
    validCoupons := make([]struct {
        code         string
        businessLine string
        isActive     bool
    }, 0)

    for i := 0; i < len(code); i++ {
