        if isValidCode && isValidBusiness && isActive[i] {
            validCoupons = append(validCoupons, struct {
                code         string
                businessLine string
                isActive     bool
            }{
                code:         code[i],
                businessLine: businessLine[i],
                isActive:     isActive[i],
            })
        }
    }

    // Sort the valid coupons first by business line order, then by code dictionary order
    sort.Slice(validCoupons, func(i, j int) bool {
        businessIndexI := businessOrderIndexOf(businessOrder, validCoupons[i].businessLine)
        businessIndexJ := businessOrderIndexOf(businessOrder, validCoupons[j].businessLine)
        if businessIndexI != businessIndexJ {
            return businessIndexI < businessIndexJ
