func businessOrderContains(order []string, s string) bool {
    for _, item := range order {
        if item == s {
            return true
        }
    }
    return false
}

func businessOrderIndexOf(order []string, s string) int {
    for i, item := range order {
        if item == s {
            return i
        }
    }
    return -1
}
